export const 複文四己 = (bi) => {
    const u = bi.u;
    const 己 = (cx, cz) => bi.一筆({ 寬: 0.9 * u, 起: '藏', 收: '出' }, p => p.M(cx - 2.4, cz - 3.0)
        .L(cx + 1.7, cz - 3.1)
        .C(cx + 2.4, cz - 3.1, cx + 2.5, cz - 2.6, cx + 2.4, cz - 2.1)
        .C(cx + 2.3, cz - 1.6, cx + 1.8, cz - 1.2, cx + 1.1, cz - 1.15)
        .L(cx - 1.8, cz - 1.05)
        .C(cx - 2.4, cz - 1.0, cx - 2.6, cz - 0.5, cx - 2.5, cz + 0.2)
        .C(cx - 2.4, cz + 0.9, cx - 1.9, cz + 1.3, cx - 1.1, cz + 1.35)
        .L(cx + 1.5, cz + 1.45)
        .C(cx + 2.4, cz + 1.45, cx + 2.9, cz + 0.9, cx + 2.9, cz - 0.1));
    // 上排二枚：方頭雙楣（端有下杙）承 S 鉤——圖版上排頭部方整，下排純 S
    const 方頭己 = (cx, cz) => {
        bi.一筆({ 寬: 0.85 * u, 起: '藏', 收: '回' }, p => p
            .M(cx - 2.3, cz - 3.4).L(cx + 2.2, cz - 3.5).L(cx + 2.2, cz - 2.4));
        bi.一筆({ 寬: 0.85 * u, 起: '藏', 收: '回' }, p => p
            .M(cx - 2.3, cz - 3.3).L(cx - 2.3, cz - 2.3).L(cx + 1.6, cz - 2.4));
        bi.一筆({ 寬: 0.9 * u, 起: '藏', 收: '出' }, p => p
            .M(cx - 2.4, cz - 1.0)
            .L(cx + 1.4, cz - 1.1)
            .C(cx + 2.2, cz - 1.1, cx + 2.4, cz - 0.6, cx + 2.2, cz - 0.1)
            .C(cx + 2.0, cz + 0.3, cx + 1.5, cz + 0.55, cx + 0.8, cz + 0.6)
            .L(cx - 1.6, cz + 0.7)
            .C(cx - 2.3, cz + 0.75, cx - 2.5, cz + 1.25, cx - 2.3, cz + 1.75)
            .C(cx - 2.0, cz + 2.3, cx - 1.3, cz + 2.55, cx - 0.4, cz + 2.6)
            .L(cx + 1.7, cz + 2.65)
            .C(cx + 2.5, cz + 2.65, cx + 2.9, cz + 2.2, cx + 2.9, cz + 1.4));
    };
    方頭己(-3.6, 6.9);
    方頭己(3.6, 6.7);
    己(-3.6, 15.7);
    己(3.6, 15.5);
};
